#!/bin/bash
echo '' | base64 -d > /opt/charge-goertz/app.py
systemctl daemon-reload
systemctl enable charge-goertz --quiet 2>/dev/null || true
systemctl restart charge-goertz
sleep 2
systemctl is-active --quiet charge-goertz && echo "✓ Service laeuft!" || echo "Fehler: journalctl -u charge-goertz -n 20"
systemctl restart nginx 2>/dev/null || true
IP=$(hostname -I | awk '{print $1}')
echo "App: http://$IP:8080"
echo "API: http://$IP:5000/api/status"
